const FORBIDDEN = ["Love your recent post", "Love your content", "Your content is amazing", "Great post about", "Hope this finds you well", "I hope you're doing well", "Just wanted to reach out", "I wanted to reach out", "I came across your profile", "I noticed you're", "I saw that you", "Reaching out because", "Big fan of", "I found something crazy", "You won't believe what", "I have a secret", "Something interesting about your business", "Something surprising", "I noticed a weird thing", "Curious about something I found", "Hop on a quick call", "Jump on a call", "Get on a call", "Book a call", "Free strategy session", "Complimentary audit", "No obligation", "Discounted rate", "Limited time", "Special offer", "Just checking in", "Following up", "Circling back", "Bumping this", "Wanted to touch base", "Touch base", "Quick question", "Delve into", "In the realm of", "Tapestry", "Symphony", "Testament to", "Meticulously", "It's worth noting"];
const respBody = $json;
let text = '';
try { text = (respBody.content || []).filter(b => b.type === 'text').map(b => b.text).join(''); } catch (e) {}
let parsed;
try { parsed = JSON.parse((text || '').replace(/```json|```/g, '').trim()); }
catch (e) { throw new Error('malformed_json_from_model'); }
const job = $('Loop jobs').item.json;
const isDm = job.is_dm;
const msgs = parsed.messages || [];
if (!Array.isArray(msgs) || msgs.length === 0) throw new Error('no_messages');
const expected = isDm ? 3 : 4;
if (msgs.length !== expected) throw new Error('expected_' + expected + '_messages_got_' + msgs.length);
const gap = (job.payload.gap_summary || '').toLowerCase();
const gapWords = gap.split(/[^a-z0-9]+/).filter(w => w.length > 4);
const rows = [];
for (const m of msgs) {
  if (!m.body) throw new Error('empty_body_step_' + m.step);
  let stored = m.body;
  if (!isDm) {
    if (!m.subject) throw new Error('email_missing_subject_step_' + m.step);
    stored = 'Subject: ' + m.subject + '\n\n' + m.body;
  }
  const lc = (m.body + ' ' + (m.subject || '')).toLowerCase();
  for (const p of FORBIDDEN) { if (lc.includes(p.toLowerCase())) throw new Error('forbidden_phrase:' + p + '@' + m.step); }
  if (m.body.includes(' \u2014 ')) throw new Error('em_dash@' + m.step);
  if (m.body.includes('!!!')) throw new Error('triple_bang@' + m.step);
  if (isDm && m.step === 1 && m.body.length > 160) throw new Error('msg1_over_160:' + m.body.length);
  if (m.step === 1 && gapWords.length && !gapWords.some(w => lc.includes(w))) throw new Error('step1_no_gap_reference');
  rows.push({ step: m.step, body: stored, char_count: stored.length });
}
return [{ json: { lead_id: job.lead_id, channel: job.channel, model: job.model, messages: rows } }];

